VALUES
  ('aboriginal-c5fb3965-moex-00338', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '甲乙之子女為丙，丁戊之子女為庚。丙庚結婚所生之子女為辛。辛與癸結婚後，辛與丙庚一同出遊遇 難，辛丙庚同時死亡。辛之遺產有新臺幣（下同）1,200萬元，應如何分配該繼承財產？', '["甲繼承100萬元", "丁繼承200萬元", "乙繼承300萬元", "癸繼承400萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00339', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '司法警察在下列情況下詢問犯罪嫌疑人所取得之自白，何者得作為證據？', '["於夜間未經受訊問人同意而詢問", "等候辯護人之時間已超過4小時後，辯護人尚未到場所為之詢問", "將犯罪嫌疑人解送至地方檢察署途中所為之詢問", "犯罪嫌疑人須由通譯傳譯，未等通譯4小時，通譯尚未到場前所為之詢問"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00340', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '甲涉嫌竊盜鄰居乙之財物，為警逮捕到案。下列情形，何者有證據能力？', '["甲不耐疲勞轟炸，乃自白竊盜犯行", "甲已表示選任辯護人之意思，於等候甲選擇並聯繫辯護人之期間，員警仍加以詢問，被告因而自白 竊盜犯行", "甲出於自由意志自白竊盜犯行，且與事實相符", "乙以證人身分於檢察官訊問時作證，卻未具結"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00341', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '刑事訴訟法第293條前段規定，審判非一次期日所能終結者，除有特別情形外，應於次日連續開庭。 此規定係落實下列何種原則？', '["繼續審理原則", "直接審理原則", "公開審理原則", "言詞審理原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00342', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '刑事案件被告之羈押，由何人負責審查決定？', '["法官", "檢察官", "司法警察官", "檢察總長"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00343', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列關於故意或過失之敘述，何者錯誤？', '["對於行為之處罰，應有故意或過失始可", "過失行為之處罰，應有法律之明文規定", "行為人按其情節應注意，並能注意，而不注意者，為故意", "行為人對於構成犯罪之事實，明知並有意使其發生者，為故意"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00344', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '因身分或其他特定關係成立之罪，其共同實行、教唆或幫助者，雖無特定關係，依刑法第 31 條第 1 項，應如何論處？', '["仍以正犯或共犯論", "仍以故意犯或過失犯論", "以加重結果犯論", "以不作為犯論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00345', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列關於自首之敘述，何者錯誤？', '["須偵查機關尚未發覺犯罪行為人前為之", "行為人有接受裁判之意思", "僅限現行犯始能適用自首", "自首得減輕其刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00346', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '刑法第15條第1項規定：「對於犯罪結果之發生，法律上有防止之義務，能防止而不防止者，與因積 極行為發生結果者同。」此一規定係指下列何種犯罪類型？', '["加重結果犯", "不作為犯", "身分犯", "未遂犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00347', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '刑法第17條規定：「因犯罪致發生一定之結果，而有加重其刑之規定者，如行為人不能預見其發生時， 不適用之。」此一規定係指下列何種犯罪類型？', '["不作為犯", "過失犯", "故意犯", "加重結果犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
